const staticData = $getWorkflowStaticData("global");
const cfData = $("Fetch Codeforces").first().json.result || [];
const lcData = $("Fetch LeetCode").first().json.data.topTwoContests || [];

const now = Math.floor(Date.now() / 1000);
const d = new Date();
const currentDay = d.getDay(); // 0=Sun, 1=Mon, 4=Thu
const currentHour = d.getHours(); 
const todayStr = d.toISOString().split("T")[0];

let message = "";
let send = false;

// Format helper
function getTimeRemaining(startTime) {
  const diff = startTime - now;
  const days = Math.floor(diff / (24 * 60 * 60));
  const hours = Math.floor((diff % (24 * 60 * 60)) / (60 * 60));
  if (days === 0 && hours === 0) return "in less than an hour!";
  if (days === 0) return `in ${hours} hour${hours > 1 ? "s" : ""}`;
  if (hours === 0) return `in ${days} day${days > 1 ? "s" : ""}`;
  return `in ${days} day${days > 1 ? "s" : ""} and ${hours} hour${hours > 1 ? "s" : ""}`;
}

// Find next contests
const cfUpcoming = cfData.filter(c => c.phase === "BEFORE" && c.startTimeSeconds >= now);
cfUpcoming.sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);
const nextCf = cfUpcoming.length > 0 ? cfUpcoming[0] : null;

const lcUpcoming = lcData.filter(c => c.startTime >= now);
lcUpcoming.sort((a, b) => a.startTime - b.startTime);
const nextLc = lcUpcoming.length > 0 ? lcUpcoming[0] : null;

let oneHourAlerts = [];
let todayAlerts = [];

// Check Codeforces
if (nextCf) {
  const diff = nextCf.startTimeSeconds - now;
  if (diff > 0 && diff <= 75 * 60) oneHourAlerts.push(`*Codeforces:* ${nextCf.name}`);
  if (diff > 0 && diff <= 24 * 3600) todayAlerts.push(`*Codeforces:* ${nextCf.name} (Starts ${getTimeRemaining(nextCf.startTimeSeconds)})`);
}
// Check LeetCode
if (nextLc) {
  const diff = nextLc.startTime - now;
  if (diff > 0 && diff <= 75 * 60) oneHourAlerts.push(`*LeetCode:* ${nextLc.title}`);
  if (diff > 0 && diff <= 24 * 3600) todayAlerts.push(`*LeetCode:* ${nextLc.title} (Starts ${getTimeRemaining(nextLc.startTime)})`);
}

// Evaluate Conditions with Memory
if (oneHourAlerts.length > 0) {
  // Always send emergency 1-hour alert if laptop happens to be awake
  message = "🔥 *CONTEST STARTING IN 1 HOUR!* 🔥\n\n" + oneHourAlerts.join("\n");
  send = true;
} 
else if (todayAlerts.length > 0 && staticData.lastContestDay !== todayStr) {
  // Send "Contest Today" alert if we haven't sent it yet today
  message = "🌅 *Contest Today!* Good luck:\n\n" + todayAlerts.join("\n");
  staticData.lastContestDay = todayStr;
  send = true;
} 
else if ((currentDay === 1 || currentDay === 4) && currentHour >= 18 && staticData.lastWeeklyDay !== todayStr) {
  // Send Weekly Overview on Mon/Thu after 6 PM, if we haven't sent it yet today
  message = "*📅 Weekly Contest Overview*\n\n";
  if (nextCf) message += `*Codeforces:* ${nextCf.name} is ${getTimeRemaining(nextCf.startTimeSeconds)}\n`;
  if (nextLc) message += `*LeetCode:* ${nextLc.title} is ${getTimeRemaining(nextLc.startTime)}\n`;
  staticData.lastWeeklyDay = todayStr;
  send = true;
}

if (!send) {
  return []; // Stop workflow silently
}

return { message };
